interface InputBarProps {
  onSend: (text: string, images?: { data: string; mimeType: string }[], mentions?: MentionItem[]) => void
  disabled: boolean
  isConnected: boolean
  isStreaming?: boolean
  onStop?: () => void
  isLazySwitched?: boolean
  backgroundSessionName?: string | null
  isBackgroundStreaming?: boolean
  isAgentEnding?: boolean
  currentModel?: PiModelInfo | null
  onSetModel?: (modelId: string, provider?: string) => Promise<boolean>
  getAvailableModels?: () => Promise<PiModelInfo[]>
  files: FileEntry[]
}

function InputBar({ onSend, disabled, isConnected, isStreaming, onStop, isLazySwitched, backgroundSessionName, isBackgroundStreaming, isAgentEnding, currentModel, onSetModel, getAvailableModels, files }: InputBarProps): React.ReactElement {
  const [text, setText] = useState('')
  const [pastedImages, setPastedImages] = useState<{ data: string; mimeType: string }[]>([])
  const [showModelSelector, setShowModelSelector] = useState(false)
  const textareaRef = useRef<HTMLTextAreaElement>(null)

  const mention = useFileMention(files)

  const showStop = isStreaming || isBackgroundStreaming
  const noModel = isConnected && !currentModel

  const handleSubmit = useCallback((): void => {
    const trimmed = text.trim()
    if (!trimmed && pastedImages.length === 0) return
    if (disabled) return
    onSend(trimmed, pastedImages.length > 0 ? pastedImages : undefined, mention.mentions.length > 0 ? mention.mentions : undefined)
    setText('')
    setPastedImages([])
    mention.clearMentions()
    if (textareaRef.current) {
      textareaRef.current.style.height = 'auto'
    }
  }, [text, pastedImages, disabled, onSend, mention])

  function handleKeyDown(e: React.KeyboardEvent<HTMLTextAreaElement>): void {
    if (mention.onKeyDown(e)) return
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault()
      handleSubmit()
    }
  }

  function handleInput(e: React.ChangeEvent<HTMLTextAreaElement>): void {
    const value = e.target.value
    setText(value)
    mention.onTextInput(value, e.target.selectionStart ?? value.length)
    const el = e.target
    el.style.height = 'auto'
    el.style.height = Math.min(el.scrollHeight, 96) + 'px'
  }

  const handleMentionSelect = useCallback((file: FileEntry) => {
    const before = text.substring(0, mention.triggerStart)
    const after = text.substring(mention.triggerStart + 1 + mention.query.length)
    const mentionText = `@${file.name} `
    setText(before + mentionText + after)
    mention.selectItem(file)
    setTimeout(() => {
      if (textareaRef.current) {
        const newPos = before.length + mentionText.length
        textareaRef.current.setSelectionRange(newPos, newPos)
        textareaRef.current.focus()
      }
    }, 0)
  }, [text, mention])

  function handlePaste(e: React.ClipboardEvent): void {
    const items = e.clipboardData.items
    for (const item of items) {
      if (item.type.startsWith('image/')) {
        e.preventDefault()
        const blob = item.getAsFile()
        if (!blob) continue
        const reader = new FileReader()
        reader.onload = () => {
          const result = reader.result as string
          const match = result.match(/^data:(image\/\w+);base64,(.+)$/)
          if (match) {
            setPastedImages((prev) => [...prev, { mimeType: match[1], data: match[2] }])
          }
        }
        reader.readAsDataURL(blob)
      }
    }
  }

  let statusDot: React.ReactNode
  let statusText: React.ReactNode

  if (isAgentEnding) {
    statusDot = <svg className="h-1.5 w-1.5 animate-spin text-blue-500" viewBox="0 0 24 24" fill="none"><circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4" /><path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4z" /></svg>
    statusText = <span className="text-blue-600">Switching back…</span>
  } else if (isBackgroundStreaming && backgroundSessionName) {
    statusDot = (
      <span className="relative flex h-1.5 w-1.5">
        <span className="absolute inline-flex h-full w-full animate-ping rounded-full bg-amber-400 opacity-75" />
        <span className="relative inline-flex h-1.5 w-1.5 rounded-full bg-amber-500" />
      </span>
    )
    statusText = (
      <span className="text-amber-600">
        <span className="rounded bg-amber-100 px-1.5 py-0.5 font-medium">{backgroundSessionName}</span> is running… press <kbd className="rounded border border-amber-200 bg-amber-100 px-1 py-px font-mono text-[10px] leading-none text-amber-600">Esc</kbd> to interrupt
      </span>
    )
  } else if (isStreaming) {
    statusDot = <span className="inline-block h-1.5 w-1.5 rounded-full bg-blue-500 animate-pulse" />
    statusText = <>Pi is thinking… press <kbd className="rounded border border-gray-200 bg-gray-100 px-1 py-px font-mono text-[10px] leading-none text-gray-500">Esc</kbd> to interrupt</>
  } else if (noModel) {
    statusDot = <span className="inline-block h-1.5 w-1.5 rounded-full bg-amber-500" />
    statusText = (
      <span className="text-amber-600">
        Pi Connected · <button onClick={() => setShowModelSelector(true)} className="underline decoration-amber-300 underline-offset-2 hover:decoration-amber-500 transition-colors">No model configured</button>
      </span>
    )
  } else if (isConnected && currentModel) {
    statusDot = <span className="inline-block h-1.5 w-1.5 rounded-full bg-green-500" />
    statusText = (
      <span className="text-gray-500">
        Pi Connected · <button onClick={() => setShowModelSelector(true)} className="rounded bg-gray-100 px-1.5 py-0.5 font-medium text-gray-700 hover:bg-gray-200 transition-colors">{currentModel.name}</button>
      </span>
    )
  } else {
    statusDot = <span className="inline-block h-1.5 w-1.5 rounded-full bg-red-500" />
    statusText = 'Pi Disconnected'
  }

  return (
    <div className="border-t border-gray-200 bg-white px-4 py-3 relative">
      <div className="mb-2 flex items-center gap-1.5 text-xs text-gray-400">
        {statusDot}
        {statusText}
      </div>
      {noModel && (
        <div className="mb-2 rounded-md bg-amber-50 border border-amber-200 px-3 py-1.5 text-xs text-amber-700">
          No model configured — <button onClick={() => setShowModelSelector(true)} className="underline font-medium hover:text-amber-900 transition-colors">select a model</button> to start chatting
        </div>
      )}
      {showModelSelector && onSetModel && getAvailableModels && (
        <ModelSelector
          currentModel={currentModel ?? null}
          onSetModel={onSetModel}
          getAvailableModels={getAvailableModels}
          onClose={() => setShowModelSelector(false)}
        />
      )}
      {pastedImages.length > 0 && (
        <div className="mb-2 flex gap-2">
          {pastedImages.map((img, i) => (
            <div key={i} className="relative">
              <img
                src={`data:${img.mimeType};base64,${img.data}`}
                alt="pasted"
                className="h-16 rounded border border-gray-200"
              />
              <button
                onClick={() => setPastedImages((prev) => prev.filter((_, j) => j !== i))}
                className="absolute -right-1 -top-1 flex h-4 w-4 items-center justify-center rounded-full bg-red-600 text-[10px] text-white"
              >
                ×
              </button>
            </div>
          ))}
        </div>
      )}
      <div className="flex items-end gap-2 relative">
        <div className="flex-1 relative">
          <textarea
            ref={textareaRef}
            value={text}
            onChange={handleInput}
            onKeyDown={handleKeyDown}
            onPaste={handlePaste}
            disabled={disabled || noModel}
            rows={1}
            placeholder={noModel ? 'Select a model to start chatting...' : disabled ? 'Pi not connected...' : 'Type a message... (@ to mention files)'}
            className="w-full resize-none rounded-lg border border-gray-300 bg-white px-3 py-2 text-sm text-gray-900 placeholder-gray-400 focus:outline-none focus:ring-1 focus:ring-gray-300 disabled:opacity-50"
          />
          <FileMentionDropdown
            files={mention.filteredFiles}
            selectedIndex={mention.selectedIndex}
            onSelect={handleMentionSelect}
            visible={mention.open}
          />
        </div>
        {showStop ? (
          <button
            onClick={onStop}
            className="rounded-lg bg-red-600 px-4 py-2 text-sm font-medium text-white transition-colors hover:bg-red-500 active:scale-95"
          >
            Stop
          </button>
        ) : (
          <button
            onClick={handleSubmit}
            disabled={disabled || noModel || (!text.trim() && pastedImages.length === 0)}
            className="rounded-lg bg-blue-600 px-4 py-2 text-sm font-medium text-white transition-colors hover:bg-blue-500 disabled:opacity-50 disabled:hover:bg-blue-600"
          >
            Send
          </button>
        )}
      </div>
    </div>
  )
}

export default InputBar

import { useState, useEffect, useCallback, useRef } from 'react'
import TreeGraphRow, { type GuideEntry, TREE_DEFAULTS } from './TreeGraph'
import CommitDetailInline from './CommitDetailInline'
import type { CommitEntry, CommitDetail } from '../types/git'

const BRANCH_COLORS = [
  '#3b82f6', // blue-500
  '#10b981', // emerald-500
  '#8b5cf6', // violet-500
  '#f59e0b', // amber-500
  '#ef4444', // red-500
  '#06b6d4', // cyan-500
  '#ec4899', // pink-500
  '#84cc16', // lime-500
]

function getBranchColor(branchName: string): string {
  // Simple hash to assign a stable color per branch name
  let hash = 0
  for (let i = 0; i < branchName.length; i++) {
    hash = ((hash << 5) - hash + branchName.charCodeAt(i)) | 0
  }
  return BRANCH_COLORS[Math.abs(hash) % BRANCH_COLORS.length]
}

function formatRelativeTime(dateStr: string): string {
  try {
    const now = Date.now()
    const then = new Date(dateStr).getTime()
    if (isNaN(then)) return dateStr
    const diffMs = now - then
    const diffMin = Math.floor(diffMs / 60000)
    const diffHr = Math.floor(diffMs / 3600000)
    const diffDay = Math.floor(diffMs / 86400000)

    if (diffMin < 1) return 'just now'
    if (diffMin < 60) return `${diffMin}m ago`
    if (diffHr < 24) return `${diffHr}h ago`
    if (diffDay < 30) return `${diffDay}d ago`
    return new Date(dateStr).toLocaleDateString()
  } catch {
    return dateStr
  }
}

/** Parse refs string to extract branch names and tags */
function parseRefs(refsStr: string): { branches: string[]; tags: string[]; isHead: boolean } {
  const branches: string[] = []
  const tags: string[] = []
  let isHead = false

  if (!refsStr) return { branches, tags, isHead }

  // refs format: "HEAD -> main, origin/main, tag: v1.0"
  const parts = refsStr.split(',').map(s => s.trim()).filter(Boolean)
  for (const part of parts) {
    if (part.startsWith('HEAD -> ')) {
      isHead = true
      const branch = part.replace('HEAD -> ', '').trim()
      branches.push(branch)
    } else if (part.startsWith('tag: ')) {
      tags.push(part.replace('tag: ', '').trim())
    } else {
      branches.push(part)
    }
  }

  return { branches, tags, isHead }
}

/** Determine the primary branch name for a commit (for coloring) */
function getCommitBranch(refsStr: string): string | null {
  const { branches } = parseRefs(refsStr)
  // Return the first local branch (not origin/) or null
  for (const b of branches) {
    if (!b.startsWith('origin/') && !b.startsWith('upstream/')) return b
  }
  return branches[0] ?? null
}

export default function GitLogList({
  onCommitFileSelect,
}: {
  onCommitFileSelect?: (hash: string, filePath: string) => void
}) {
  const [commits, setCommits] = useState<CommitEntry[]>([])
  const [loading, setLoading] = useState(true)
  const [loadingMore, setLoadingMore] = useState(false)
  const [error, setError] = useState<string | null>(null)
  const [expandedHash, setExpandedHash] = useState<string | null>(null)
  const [expandedDetail, setExpandedDetail] = useState<CommitDetail | null>(null)
  const [detailLoading, setDetailLoading] = useState(false)
  const [hasMore, setHasMore] = useState(true)
  const skipRef = useRef(0)

  const loadCommits = useCallback(async (skip: number, append: boolean) => {
    if (skip === 0) setLoading(true)
    else setLoadingMore(true)
    setError(null)
    try {
      const result = await window.api.gitLog({ maxCount: 50, skip })
      if (result.ok && result.data) {
        const newCommits = result.data
        if (append) {
          setCommits(prev => [...prev, ...newCommits])
        } else {
          setCommits(newCommits)
        }
        setHasMore(newCommits.length >= 50)
        skipRef.current = skip + newCommits.length
      } else {
        setError(result.error ?? 'Failed to load git log')
      }
    } catch (err) {
      setError(err instanceof Error ? err.message : String(err))
    } finally {
      setLoading(false)
      setLoadingMore(false)
    }
  }, [])

  useEffect(() => {
    loadCommits(0, false)
  }, [loadCommits])

  const handleLoadMore = useCallback(() => {
    loadCommits(skipRef.current, true)
  }, [loadCommits])

  const handleToggleCommit = useCallback(async (hash: string) => {
    if (expandedHash === hash) {
      setExpandedHash(null)
      setExpandedDetail(null)
      return
    }

    setExpandedHash(hash)
    setDetailLoading(true)
    setExpandedDetail(null)
    try {
      const result = await window.api.gitCommitDetail(hash)
      if (result.ok && result.data) {
        setExpandedDetail(result.data)
      }
    } catch {
      // Silently fail — detail will just be empty
    } finally {
      setDetailLoading(false)
    }
  }, [])

  if (loading) {
    return (
      <div className="flex items-center justify-center py-8 text-gray-400 text-xs">
        Loading log...
      </div>
    )
  }

  if (error) {
    return (
      <div className="px-3 py-4 text-gray-400 text-center">
        {error}
      </div>
    )
  }

  if (commits.length === 0) {
    return (
      <div className="px-3 py-4 text-gray-400 text-center">
        No commits found
      </div>
    )
  }

  // Track which branches have been seen to assign colors
  const branchColorMap = new Map<string, string>()
  let colorIdx = 0
  const getOrAssignColor = (branch: string): string => {
    let color = branchColorMap.get(branch)
    if (!color) {
      color = BRANCH_COLORS[colorIdx % BRANCH_COLORS.length]
      branchColorMap.set(branch, color)
      colorIdx++
    }
    return color
  }

  return (
    <div className="divide-y divide-gray-100">
      {commits.map((commit) => {
        const branch = getCommitBranch(commit.refs)
        const { branches, tags, isHead } = parseRefs(commit.refs)
        const isExpanded = expandedHash === commit.hash

        // Determine dot color
        const dotColor = branch ? getOrAssignColor(branch) : TREE_DEFAULTS.GRAY
        const dotStyle: 'filled' | 'outlined' | 'hollow' = isHead ? 'filled' : branch ? 'outlined' : 'hollow'

        // Build guides for the graph lane
        const guides: GuideEntry[] = [
          {
            type: 'dot',
            color: dotColor,
            dotStyle,
            hasLineBelow: true, // will be refined in Phase 2 with multi-lane
            lineBelowColor: TREE_DEFAULTS.GRAY,
          },
        ]

        return (
          <div key={commit.hash}>
            <div
              className="group flex items-center hover:bg-gray-100 cursor-pointer transition-colors"
              onClick={() => handleToggleCommit(commit.hash)}
            >
              <div className="flex-shrink-0">
                <TreeGraphRow guides={guides}>
                  <div className="flex-1 flex items-center gap-1.5 py-1.5 pr-2 min-w-0">
                    {/* Commit hash */}
                    <span className="font-mono text-[10px] text-gray-400 flex-shrink-0">{commit.shortHash}</span>

                    {/* Branch/tag badges */}
                    {branches.map(b => (
                      <span
                        key={b}
                        className="flex-shrink-0 px-1 py-0 rounded text-[10px] font-medium truncate max-w-[80px]"
                        style={{
                          backgroundColor: getOrAssignColor(b) + '18',
                          color: getOrAssignColor(b),
                        }}
                        title={b}
                      >
                        {b}
                      </span>
                    ))}
                    {tags.map(t => (
                      <span
                        key={t}
                        className="flex-shrink-0 px-1 py-0 rounded text-[10px] font-medium bg-amber-50 text-amber-600 truncate max-w-[80px]"
                        title={t}
                      >
                        {t}
                      </span>
                    ))}
                  </div>
                </TreeGraphRow>
              </div>
            </div>

            {/* Commit message + meta (below the hash/branch line) */}
            <div
              className="group flex items-center hover:bg-gray-100 cursor-pointer transition-colors"
              onClick={() => handleToggleCommit(commit.hash)}
            >
              {/* Left spacer matching the graph area */}
              <div className="flex-shrink-0" style={{ width: TREE_DEFAULTS.SLOT_W + 4 }} />

              <div className="flex-1 py-0.5 pr-2 min-w-0">
                <div className="text-gray-700 truncate">{commit.message}</div>
                <div className="text-[10px] text-gray-400 mt-0.5">
                  {commit.author_name} · {formatRelativeTime(commit.date)}
                </div>
              </div>

              {/* Expand/collapse indicator */}
              <div className="flex-shrink-0 px-2 text-gray-300">
                <svg
                  className={`w-3 h-3 transition-transform ${isExpanded ? 'rotate-90' : ''}`}
                  fill="currentColor"
                  viewBox="0 0 20 20"
                >
                  <path
                    fillRule="evenodd"
                    d="M7.21 14.77a.75.75 0 01.02-1.06L11.168 10 7.23 6.29a.75.75 0 111.04-1.08l4.5 4.25a.75.75 0 010 1.08l-4.5 4.25a.75.75 0 01-1.06-.02z"
                    clipRule="evenodd"
                  />
                </svg>
              </div>
            </div>

            {/* Expanded commit detail */}
            {isExpanded && (
              <CommitDetailInline
                hash={commit.hash}
                detail={expandedDetail}
                loading={detailLoading}
                onFileSelect={(filePath) => onCommitFileSelect?.(commit.hash, filePath)}
                onClose={() => {
                  setExpandedHash(null)
                  setExpandedDetail(null)
                }}
              />
            )}
          </div>
        )
      })}

      {/* Load more */}
      {hasMore && (
        <div className="px-3 py-2 text-center">
          <button
            onClick={handleLoadMore}
            disabled={loadingMore}
            className="text-xs text-blue-500 hover:text-blue-600 hover:underline disabled:text-gray-400 disabled:no-underline"
          >
            {loadingMore ? 'Loading...' : 'Load more'}
          </button>
        </div>
      )}
    </div>
  )
}

import type { CommitDetail, FileChange } from '../types/git'

function statusBadgeColor(status: string): string {
  switch (status) {
    case 'M': return 'bg-amber-50 text-amber-600'
    case 'A': return 'bg-green-50 text-green-600'
    case 'D': return 'bg-red-50 text-red-600'
    case 'R': return 'bg-blue-50 text-blue-600'
    case 'C': return 'bg-purple-50 text-purple-600'
    default: return 'bg-gray-50 text-gray-500'
  }
}

function statusBadgeLabel(status: string): string {
  switch (status) {
    case 'M': return 'M'
    case 'A': return 'A'
    case 'D': return 'D'
    case 'R': return 'R'
    case 'C': return 'C'
    default: return status
  }
}

function FileChangeItem({
  file,
  onFileSelect,
}: {
  file: FileChange
  onFileSelect: (filePath: string) => void
}) {
  return (
    <div
      className="flex items-center gap-1.5 py-0.5 px-2 hover:bg-gray-50 cursor-pointer rounded group"
      onClick={() => onFileSelect(file.path)}
      title={file.path}
    >
      <span className={`px-1 py-0 rounded text-[10px] font-mono font-semibold ${statusBadgeColor(file.status)}`}>
        {statusBadgeLabel(file.status)}
      </span>
      <span className="flex-1 truncate text-gray-600 group-hover:text-gray-900 transition-colors">
        {file.path}
      </span>
      <span className="text-[10px] text-gray-300 flex-shrink-0">
        {file.additions > 0 && <span className="text-green-500">+{file.additions}</span>}
        {file.additions > 0 && file.deletions > 0 && <span className="text-gray-300">/</span>}
        {file.deletions > 0 && <span className="text-red-400">-{file.deletions}</span>}
      </span>
      <svg
        className="w-3 h-3 text-gray-300 group-hover:text-gray-500 flex-shrink-0 transition-colors"
        fill="none"
        viewBox="0 0 24 24"
        stroke="currentColor"
        strokeWidth={2}
      >
        <path strokeLinecap="round" strokeLinejoin="round" d="M9 5l7 7-7 7" />
      </svg>
    </div>
  )
}

export default function CommitDetailInline({
  hash,
  detail,
  loading,
  onFileSelect,
  onClose,
}: {
  hash: string
  detail: CommitDetail | null
  loading: boolean
  onFileSelect: (filePath: string) => void
  onClose: () => void
}) {
  return (
    <div className="border-t border-b border-gray-200 bg-gray-50/50">
      {/* Header with close button */}
      <div className="flex items-center justify-between px-3 pt-2 pb-1">
        <span className="font-mono text-[10px] text-gray-400">{hash}</span>
        <button
          onClick={(e) => {
            e.stopPropagation()
            onClose()
          }}
          className="rounded p-0.5 text-gray-400 hover:text-gray-600 hover:bg-gray-200 transition-colors"
          title="Close"
        >
          <svg className="w-3 h-3" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2}>
            <path strokeLinecap="round" strokeLinejoin="round" d="M6 18L18 6M6 6l12 12" />
          </svg>
        </button>
      </div>

      {loading && (
        <div className="px-3 pb-2 text-gray-400 text-[10px]">Loading details...</div>
      )}

      {!loading && detail && (
        <div className="px-3 pb-2">
          {/* Full message */}
          {detail.body && (
            <div className="text-gray-500 text-[11px] mt-0.5 mb-1 whitespace-pre-wrap">
              {detail.body}
            </div>
          )}

          {/* Author & date */}
          <div className="text-[10px] text-gray-400 flex items-center gap-2 mb-2">
            <span>{detail.author_name}</span>
            {detail.author_email && (
              <span className="text-gray-300">&lt;{detail.author_email}&gt;</span>
            )}
            <span>·</span>
            <span>{new Date(detail.date).toLocaleString()}</span>
          </div>

          {/* Changed files */}
          {detail.files.length > 0 && (
            <div>
              <div className="text-[10px] text-gray-500 font-medium mb-1">
                Changed files ({detail.files.length})
              </div>
              <div className="space-y-0.5">
                {detail.files.map((file) => (
                  <FileChangeItem
                    key={file.path}
                    file={file}
                    onFileSelect={onFileSelect}
                  />
                ))}
              </div>
            </div>
          )}

          {detail.files.length === 0 && (
            <div className="text-[10px] text-gray-400">No file changes in this commit</div>
          )}
        </div>
      )}

      {!loading && !detail && (
        <div className="px-3 pb-2 text-gray-400 text-[10px]">Failed to load commit details</div>
      )}
    </div>
  )
}

/**
 * TreeGraph — reusable tree/graph guide-line component.
 *
 * Renders a row of visual "slots" (vertical lines, branch elbows, dots, etc.)
 * followed by arbitrary children content. Used by SessionSidebar and GitLogList.
 */

export interface GuideEntry {
  type: 'line' | 'branch' | 'elbow' | 'slot' | 'dot'
  /** Primary color for lines, corners, and dots. Defaults to GRAY. */
  color?: string
  /** Only for 'branch': color of the continuation line below the branch corner. Defaults to GRAY. */
  continuationColor?: string
  /** Only for 'dot': dot visual style */
  dotStyle?: 'filled' | 'outlined' | 'hollow'
  /** Only for 'dot': whether to draw a line below the dot (e.g. has expanded children) */
  hasLineBelow?: boolean
  /** Only for 'dot': color of the line below. Defaults to color or GRAY. */
  lineBelowColor?: string
}

export const TREE_DEFAULTS = {
  SLOT_W: 16,
  LINE_LEFT: 8,
  DOT_R: 3,
  GRAY: '#e5e7eb',
  BLUE: '#3b82f6',
} as const

interface TreeGraphRowProps {
  guides: GuideEntry[]
  slotWidth?: number
  lineLeft?: number
  dotRadius?: number
  children: React.ReactNode
}

function GuideLineSlot({
  color,
  slotWidth,
  lineLeft,
}: {
  color: string
  slotWidth: number
  lineLeft: number
}) {
  return (
    <div
      className="flex-shrink-0 relative pointer-events-none"
      style={{ width: slotWidth, alignSelf: 'stretch' }}
    >
      <div
        className="absolute"
        style={{ left: lineLeft, top: 0, bottom: 0, width: 1.5, backgroundColor: color }}
      />
    </div>
  )
}

function GuideBranchSlot({
  color,
  continuationColor,
  slotWidth,
  lineLeft,
  dotRadius,
}: {
  color: string
  continuationColor: string
  slotWidth: number
  lineLeft: number
  dotRadius: number
}) {
  return (
    <div
      className="flex-shrink-0 relative pointer-events-none overflow-visible"
      style={{ width: slotWidth, alignSelf: 'stretch' }}
    >
      {/* Vertical line above corner */}
      <div
        className="absolute"
        style={{ left: lineLeft, top: 0, height: `calc(50% - ${dotRadius}px)`, width: 1.5, backgroundColor: color }}
      />
      {/* Corner piece */}
      <div
        className="absolute"
        style={{
          left: lineLeft,
          top: `calc(50% - ${dotRadius}px)`,
          width: dotRadius,
          height: dotRadius,
          borderLeft: `1.5px solid ${color}`,
          borderBottom: `1.5px solid ${color}`,
          borderBottomLeftRadius: dotRadius,
        }}
      />
      {/* Horizontal line from corner to content */}
      <div
        className="absolute"
        style={{
          left: lineLeft + dotRadius,
          top: `calc(50% - 1.5px)`,
          width: slotWidth - lineLeft - dotRadius + 3,
          height: 1.5,
          backgroundColor: color,
        }}
      />
      {/* Continuation line below (parent line) */}
      <div
        className="absolute"
        style={{ left: lineLeft, top: '50%', bottom: 0, width: 1.5, backgroundColor: continuationColor }}
      />
    </div>
  )
}

function GuideElbowSlot({
  color,
  slotWidth,
  lineLeft,
  dotRadius,
}: {
  color: string
  slotWidth: number
  lineLeft: number
  dotRadius: number
}) {
  return (
    <div
      className="flex-shrink-0 relative pointer-events-none overflow-visible"
      style={{ width: slotWidth, alignSelf: 'stretch' }}
    >
      {/* Vertical line above corner */}
      <div
        className="absolute"
        style={{ left: lineLeft, top: 0, height: `calc(50% - ${dotRadius}px)`, width: 1.5, backgroundColor: color }}
      />
      {/* Corner piece */}
      <div
        className="absolute"
        style={{
          left: lineLeft,
          top: `calc(50% - ${dotRadius}px)`,
          width: dotRadius,
          height: dotRadius,
          borderLeft: `1.5px solid ${color}`,
          borderBottom: `1.5px solid ${color}`,
          borderBottomLeftRadius: dotRadius,
        }}
      />
      {/* Horizontal line from corner to content */}
      <div
        className="absolute"
        style={{
          left: lineLeft + dotRadius,
          top: `calc(50% - 1.5px)`,
          width: slotWidth - lineLeft - dotRadius + 3,
          height: 1.5,
          backgroundColor: color,
        }}
      />
    </div>
  )
}

function GuideSlotSpacer({ slotWidth }: { slotWidth: number }) {
  return (
    <div
      className="flex-shrink-0"
      style={{ width: slotWidth, alignSelf: 'stretch' }}
    />
  )
}

function DotSlot({
  color,
  dotStyle,
  hasLineBelow,
  lineBelowColor,
  slotWidth,
  dotRadius,
  defaultGray,
}: {
  color: string
  dotStyle: 'filled' | 'outlined' | 'hollow'
  hasLineBelow: boolean
  lineBelowColor: string
  slotWidth: number
  dotRadius: number
  defaultGray: string
}) {
  const size = dotRadius * 2 + 1 // e.g. 7px for R=3
  const borderWidth = 2

  const dotClass =
    dotStyle === 'filled'
      ? 'rounded-full flex-shrink-0'
      : dotStyle === 'hollow'
        ? 'rounded-full flex-shrink-0'
        : 'rounded-full flex-shrink-0' // 'outlined'

  const dotStyleCSS: React.CSSProperties =
    dotStyle === 'filled'
      ? { width: size, height: size, backgroundColor: color, border: `${borderWidth}px solid ${color}` }
      : dotStyle === 'hollow'
        ? { width: size, height: size, backgroundColor: defaultGray, border: `${borderWidth}px solid ${defaultGray}` }
        : { width: size, height: size, backgroundColor: 'white', border: `${borderWidth}px solid ${color}` }

  return (
    <div
      className="flex-shrink-0 flex items-center justify-center relative"
      style={{ width: slotWidth, alignSelf: 'stretch' }}
    >
      <div className={dotClass} style={dotStyleCSS} />
      {hasLineBelow && (
        <div
          className="absolute"
          style={{
            left: slotWidth / 2 - 0.75,
            top: `calc(50% + ${dotRadius + 2}px)`,
            bottom: 0,
            width: 1.5,
            backgroundColor: lineBelowColor,
          }}
        />
      )}
    </div>
  )
}

/**
 * Renders one row of a tree/graph with guide lines and a content area.
 *
 * Usage:
 * ```tsx
 * <TreeGraphRow guides={[
 *   { type: 'line', color: '#e5e7eb' },
 *   { type: 'dot', color: '#3b82f6', dotStyle: 'filled', hasLineBelow: true },
 * ]}>
 *   <span>Node content here</span>
 * </TreeGraphRow>
 * ```
 */
export default function TreeGraphRow({
  guides,
  slotWidth = TREE_DEFAULTS.SLOT_W,
  lineLeft = TREE_DEFAULTS.LINE_LEFT,
  dotRadius = TREE_DEFAULTS.DOT_R,
  children,
}: TreeGraphRowProps) {
  const gray = TREE_DEFAULTS.GRAY

  return (
    <div className="flex items-center">
      {guides.map((entry, i) => {
        const c = entry.color ?? gray
        switch (entry.type) {
          case 'line':
            return <GuideLineSlot key={i} color={c} slotWidth={slotWidth} lineLeft={lineLeft} />
          case 'branch':
            return (
              <GuideBranchSlot
                key={i}
                color={c}
                continuationColor={entry.continuationColor ?? gray}
                slotWidth={slotWidth}
                lineLeft={lineLeft}
                dotRadius={dotRadius}
              />
            )
          case 'elbow':
            return <GuideElbowSlot key={i} color={c} slotWidth={slotWidth} lineLeft={lineLeft} dotRadius={dotRadius} />
          case 'slot':
            return <GuideSlotSpacer key={i} slotWidth={slotWidth} />
          case 'dot':
            return (
              <DotSlot
                key={i}
                color={c}
                dotStyle={entry.dotStyle ?? 'outlined'}
                hasLineBelow={entry.hasLineBelow ?? false}
                lineBelowColor={entry.lineBelowColor ?? c}
                slotWidth={slotWidth}
                dotRadius={dotRadius}
                defaultGray={gray}
              />
            )
          default:
            return null
        }
      })}
      <div className="flex-1 flex items-center min-w-0">{children}</div>
    </div>
  )
}

/**
 * Convert session sidebar ancestorLines to GuideEntry[] for TreeGraphRow.
 * This is a convenience adapter for the SessionSidebar refactoring.
 */
export function sessionAncestorLinesToGuides(
  ancestorLines: { hasLine: boolean; highlight: boolean; branchActive: boolean }[],
): GuideEntry[] {
  const { GRAY, BLUE } = TREE_DEFAULTS
  const guides: GuideEntry[] = []

  for (let i = 0; i < ancestorLines.length; i++) {
    const entry = ancestorLines[i]
    const isConnector = i === ancestorLines.length - 1

    if (isConnector) {
      // Connector slot: branch (has sibling below) or elbow (last child)
      const color = entry.branchActive ? BLUE : GRAY
      if (entry.hasLine) {
        guides.push({ type: 'branch', color, continuationColor: GRAY })
      } else {
        guides.push({ type: 'elbow', color })
      }
    } else {
      // Ancestor slot: line or spacer
      if (entry.hasLine) {
        guides.push({ type: 'line', color: entry.highlight && !entry.branchActive ? BLUE : GRAY })
      } else {
        guides.push({ type: 'slot' })
      }
    }
  }

  return guides
}

/**
 * Convert session sidebar dot props to a GuideEntry for TreeGraphRow.
 */
export function sessionDotToGuide(props: {
  active: boolean
  hasChildren: boolean
  isExpanded: boolean
  highlight: boolean
  completed: boolean
}): GuideEntry {
  const { BLUE, GRAY } = TREE_DEFAULTS
  const { active, hasChildren, isExpanded, highlight, completed } = props

  let dotStyle: 'filled' | 'outlined' | 'hollow'
  let color: string

  if (active) {
    dotStyle = 'filled'
    color = BLUE
  } else if (completed) {
    dotStyle = 'hollow'
    color = GRAY
  } else {
    dotStyle = 'outlined'
    color = BLUE // hover color effect is handled via CSS group-hover
  }

  return {
    type: 'dot',
    color,
    dotStyle,
    hasLineBelow: hasChildren && isExpanded,
    lineBelowColor: highlight ? BLUE : GRAY,
  }
}

import { useState, useCallback, useEffect } from 'react'
import type { SessionListResult, SessionInfo, SessionTreeNode } from '../types/session'
import TreeGraphRow, { sessionAncestorLinesToGuides, sessionDotToGuide } from './TreeGraph'

interface SessionSidebarProps {
  sessions: SessionListResult | null
  currentSession: SessionInfo | null
  onSwitchSession: (sessionPath: string) => void
  onNewSession: (name: string, parentSessionPath: string) => void
  onRenameSession: (name: string) => void
  onDeleteSession: (sessionPath: string) => Promise<boolean>
  onSetSessionStatus: (sessionPath: string, status: 'active' | 'completed') => Promise<boolean>
  onForkFromEnd: (sessionPath: string, name: string) => void
  isCollapsed: boolean
  onToggleCollapse: () => void
  width: number
  onResizeStart: (e: React.MouseEvent) => void
}

function formatRelativeTime(isoTimestamp: string): string {
  const now = Date.now()
  const then = new Date(isoTimestamp).getTime()
  const diffMs = now - then
  const diffMin = Math.floor(diffMs / 60000)
  const diffHr = Math.floor(diffMs / 3600000)
  const diffDay = Math.floor(diffMs / 86400000)

  if (diffMin < 1) return 'just now'
  if (diffMin < 60) return `${diffMin}m ago`
  if (diffHr < 24) return `${diffHr}h ago`
  if (diffDay < 30) return `${diffDay}d ago`
  return new Date(isoTimestamp).toLocaleDateString()
}

function getDisplayName(session: SessionInfo): string {
  if (session.name) return session.name
  const d = new Date(session.createdAt)
  const month = d.toLocaleString('en', { month: 'short' })
  const day = d.getDate()
  const hh = String(d.getHours()).padStart(2, '0')
  const mm = String(d.getMinutes()).padStart(2, '0')
  return `${month} ${day} ${hh}:${mm}`
}

const GRAY = '#e5e7eb'
const BLUE = '#3b82f6'

function isDescendantOf(node: SessionTreeNode, sessionPath: string | null): boolean {
  if (!sessionPath) return false
  if (node.session.filePath === sessionPath) return true
  return node.children.some((child) => isDescendantOf(child, sessionPath))
}



function SessionNode({
  node,
  ancestorLines,
  currentSessionPath,
  isOnActivePath,
  onSwitch,
  onRename,
  onDelete,
  onSetSessionStatus,
  onForkFromEnd,
  onNewSession,
  onContextMenu,
  triggerRenamePath,
  onRenameTriggered,
  triggerForkPath,
  onForkTriggered,
}: {
  node: SessionTreeNode
  ancestorLines: { hasLine: boolean; highlight: boolean; branchActive: boolean }[]
  currentSessionPath: string | null
  isOnActivePath: boolean
  onSwitch: (path: string) => void
  onRename: (name: string) => void
  onDelete: (path: string) => Promise<boolean>
  onSetSessionStatus: (sessionPath: string, status: 'active' | 'completed') => Promise<boolean>
  onForkFromEnd: (sessionPath: string, name: string) => void
  onNewSession: (name: string, parentSessionPath: string) => void
  onContextMenu: (e: React.MouseEvent, session: SessionInfo) => void
  triggerRenamePath: string | null
  onRenameTriggered: () => void
  triggerForkPath: string | null
  onForkTriggered: () => void
}): React.ReactElement {
  const [isExpanded, setIsExpanded] = useState(true)
  const [isRenaming, setIsRenaming] = useState(false)
  const [renameValue, setRenameValue] = useState(getDisplayName(node.session))
  const [confirmDelete, setConfirmDelete] = useState(false)
  const [isForking, setIsForking] = useState(false)
  const [forkName, setForkName] = useState('')
  const [isCreatingChild, setIsCreatingChild] = useState(false)
  const [childName, setChildName] = useState('')
  const isCompleted = node.session.status === 'completed'
  const isActive = currentSessionPath === node.session.filePath
  const hasChildren = node.children.length > 0

  useEffect(() => {
    if (triggerRenamePath === node.session.filePath) {
      setIsRenaming(true)
      setRenameValue(getDisplayName(node.session))
      onRenameTriggered()
    }
  }, [triggerRenamePath, node.session.filePath, onRenameTriggered])

  useEffect(() => {
    if (triggerForkPath === node.session.filePath) {
      setIsForking(true)
      setForkName('')
      onForkTriggered()
    }
  }, [triggerForkPath, node.session.filePath, onForkTriggered])

  const handleDoubleClick = useCallback(() => {
    setIsRenaming(true)
    setRenameValue(getDisplayName(node.session))
  }, [node.session])

  const handleRenameSubmit = useCallback(() => {
    const trimmed = renameValue.trim()
    if (trimmed && trimmed !== getDisplayName(node.session)) {
      onRename(trimmed)
    }
    setIsRenaming(false)
  }, [renameValue, node.session, onRename])

  const hasChildOnActivePath = node.children.some(
    (child) =>
      currentSessionPath === child.session.filePath ||
      isDescendantOf(child, currentSessionPath)
  )

  const guides = [...sessionAncestorLinesToGuides(ancestorLines), sessionDotToGuide({
    active: isOnActivePath || isActive || node.session.isMain,
    hasChildren,
    isExpanded,
    highlight: hasChildOnActivePath,
    completed: isCompleted,
  })]

  return (
    <div>
      <div
        className={`group flex items-center rounded cursor-pointer transition-colors ${
          isActive
            ? isCompleted
              ? 'bg-gray-100 text-gray-400'
              : 'bg-gray-100 text-gray-900'
            : isCompleted
              ? 'text-gray-400 hover:bg-gray-100/60 hover:text-gray-500'
              : 'text-gray-600 hover:bg-gray-100/60 hover:text-gray-800'
        }`}
        onClick={() => onSwitch(node.session.filePath)}
        onDoubleClick={handleDoubleClick}
        onContextMenu={(e) => onContextMenu(e, node.session)}
      >
        <TreeGraphRow guides={guides}>
          <div className="flex-1 flex items-center gap-1 py-1.5 pr-2 min-w-0">
          {isRenaming ? (
            <input
              autoFocus
              value={renameValue}
              onChange={(e) => setRenameValue(e.target.value)}
              onBlur={handleRenameSubmit}
              onKeyDown={(e) => {
                if (e.key === 'Enter') handleRenameSubmit()
                if (e.key === 'Escape') setIsRenaming(false)
              }}
              onClick={(e) => e.stopPropagation()}
              className="flex-1 min-w-0 bg-gray-100 rounded px-1 py-0.5 text-xs text-gray-900 outline-none border border-gray-300 focus:border-blue-500"
            />
          ) : (
            <span className={`flex-1 truncate text-xs ${isCompleted ? 'line-through' : ''}`}>
              {getDisplayName(node.session)}
            </span>
          )}

          <span className="flex-shrink-0 text-[10px] text-gray-400 opacity-0 group-hover:opacity-100 transition-opacity">
            {formatRelativeTime(node.session.createdAt)}
          </span>

          {hasChildren && (
            <button
              onClick={(e) => {
                e.stopPropagation()
                setIsExpanded(!isExpanded)
              }}
              className="flex-shrink-0 rounded px-0.5 py-0.5 text-gray-400 hover:text-gray-600 hover:bg-gray-100 opacity-0 group-hover:opacity-100 transition-colors"
              title={isExpanded ? 'Collapse' : 'Expand'}
            >
              <svg
                className={`w-3 h-3 transition-transform ${isExpanded ? 'rotate-90' : ''}`}
                fill="currentColor"
                viewBox="0 0 20 20"
              >
                <path
                  fillRule="evenodd"
                  d="M7.21 14.77a.75.75 0 01.02-1.06L11.168 10 7.23 6.29a.75.75 0 111.04-1.08l4.5 4.25a.75.75 0 010 1.08l-4.5 4.25a.75.75 0 01-1.06-.02z"
                  clipRule="evenodd"
                />
              </svg>
            </button>
          )}

          {node.session.parentSessionPath && (
            <button
              onClick={(e) => {
                e.stopPropagation()
                onSwitch(node.session.parentSessionPath!)
              }}
              className="flex-shrink-0 rounded px-0.5 py-0.5 text-gray-400 hover:text-blue-500 hover:bg-gray-100 opacity-0 group-hover:opacity-100 transition-colors"
              title="Go to parent session"
            >
              <svg className="w-3.5 h-3.5" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2}>
                <path strokeLinecap="round" strokeLinejoin="round" d="M5 15l7-7 7 7" />
              </svg>
            </button>
          )}

          {isActive && (
            <button
              onClick={(e) => {
                e.stopPropagation()
                setIsForking(true)
                setForkName('')
              }}
              className="flex-shrink-0 rounded px-0.5 py-0.5 text-gray-400 hover:text-purple-500 hover:bg-gray-100 opacity-0 group-hover:opacity-100 transition-colors"
              title="Fork"
            >
              <svg className="w-3.5 h-3.5" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2}>
                <path strokeLinecap="round" strokeLinejoin="round" d="M5 12h4m6 0h4M12 5v4m0 6v4" />
                <circle cx="5" cy="12" r="2" />
                <circle cx="19" cy="12" r="2" />
                <circle cx="12" cy="5" r="2" />
                <circle cx="12" cy="19" r="2" />
              </svg>
            </button>
          )}

          <button
            onClick={(e) => {
              e.stopPropagation()
              setIsCreatingChild(true)
              setChildName('')
            }}
            className="flex-shrink-0 rounded px-0.5 py-0.5 text-gray-400 hover:text-blue-500 hover:bg-gray-100 opacity-0 group-hover:opacity-100 transition-colors"
            title="New child session"
          >
            <svg className="w-3.5 h-3.5" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2}>
              <path strokeLinecap="round" strokeLinejoin="round" d="M12 4v16m8-8H4" />
            </svg>
          </button>

          {!node.session.isMain && (
            <button
              onClick={(e) => {
                e.stopPropagation()
                if (confirmDelete) {
                  onDelete(node.session.filePath)
                  setConfirmDelete(false)
                } else {
                  setConfirmDelete(true)
                }
              }}
              onBlur={() => setConfirmDelete(false)}
              className={`flex-shrink-0 rounded p-0.5 opacity-0 group-hover:opacity-100 transition-colors ${
                confirmDelete
                  ? 'bg-red-600 text-white opacity-100'
                  : 'text-gray-400 hover:text-red-500 hover:bg-gray-100'
              }`}
            >
              {confirmDelete ? (
                <svg className="w-3.5 h-3.5" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2}>
                  <path strokeLinecap="round" strokeLinejoin="round" d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" />
                </svg>
              ) : (
                <svg className="w-3.5 h-3.5" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2}>
                  <path strokeLinecap="round" strokeLinejoin="round" d="M6 18L18 6M6 6l12 12" />
                </svg>
              )}
            </button>
          )}
          </div>
        </TreeGraphRow>
      </div>

      {isForking && (
        <div
          className="flex items-center gap-1 pl-8 pr-2 py-1"
          onClick={(e) => e.stopPropagation()}
        >
          <input
            autoFocus
            value={forkName}
            onChange={(e) => setForkName(e.target.value)}
            onKeyDown={(e) => {
              if (e.key === 'Enter') {
                const trimmed = forkName.trim()
                if (trimmed) {
                  onForkFromEnd(node.session.filePath, trimmed)
                  setIsForking(false)
                  setForkName('')
                }
              }
              if (e.key === 'Escape') {
                setIsForking(false)
                setForkName('')
              }
            }}
            placeholder="Fork name"
            className="flex-1 min-w-0 rounded border border-purple-300 bg-white px-2 py-0.5 text-xs text-gray-900 outline-none focus:border-purple-500"
          />
          <button
            onClick={() => {
              const trimmed = forkName.trim()
              if (trimmed) {
                onForkFromEnd(node.session.filePath, trimmed)
                setIsForking(false)
                setForkName('')
              }
            }}
            disabled={!forkName.trim()}
            className="rounded bg-purple-600 px-2 py-0.5 text-xs font-medium text-white hover:bg-purple-500 disabled:opacity-40 disabled:cursor-not-allowed"
          >
            Fork
          </button>
          <button
            onClick={() => {
              setIsForking(false)
              setForkName('')
            }}
            className="rounded px-1 py-0.5 text-gray-400 hover:text-gray-600 hover:bg-gray-100 text-xs transition-colors"
            title="Cancel"
          >
            ✕
          </button>
        </div>
      )}

      {isCreatingChild && (
        <div
          className="flex items-center gap-1 pl-8 pr-2 py-1"
          onClick={(e) => e.stopPropagation()}
        >
          <input
            autoFocus
            value={childName}
            onChange={(e) => setChildName(e.target.value)}
            onKeyDown={(e) => {
              if (e.key === 'Enter') {
                const trimmed = childName.trim()
                if (trimmed) {
                  onNewSession(trimmed, node.session.filePath)
                  setIsCreatingChild(false)
                  setChildName('')
                }
              }
              if (e.key === 'Escape') {
                setIsCreatingChild(false)
                setChildName('')
              }
            }}
            placeholder="Child session name"
            className="flex-1 min-w-0 rounded border border-blue-300 bg-white px-2 py-0.5 text-xs text-gray-900 outline-none focus:border-blue-500"
          />
          <button
            onClick={() => {
              const trimmed = childName.trim()
              if (trimmed) {
                onNewSession(trimmed, node.session.filePath)
                setIsCreatingChild(false)
                setChildName('')
              }
            }}
            disabled={!childName.trim()}
            className="rounded bg-blue-600 px-2 py-0.5 text-xs font-medium text-white hover:bg-blue-500 disabled:opacity-40 disabled:cursor-not-allowed"
          >
            Create
          </button>
          <button
            onClick={() => {
              setIsCreatingChild(false)
              setChildName('')
            }}
            className="rounded px-1 py-0.5 text-gray-400 hover:text-gray-600 hover:bg-gray-100 text-xs transition-colors"
            title="Cancel"
          >
            ✕
          </button>
        </div>
      )}

      {hasChildren && isExpanded && (
        <div>
          {node.children.map((child, i) => {
            const childIsActivePath =
              currentSessionPath === child.session.filePath ||
              isDescendantOf(child, currentSessionPath)
            const laterSiblingOnActivePath = node.children
              .slice(i + 1)
              .some(
                (sibling) =>
                  currentSessionPath === sibling.session.filePath ||
                  isDescendantOf(sibling, currentSessionPath)
              )
            const onPath = childIsActivePath || laterSiblingOnActivePath
            const newAncestorLines = [
              ...ancestorLines.map((entry) => ({
                hasLine: entry.hasLine,
                highlight: entry.branchActive
                  ? (entry.highlight && childIsActivePath)
                  : entry.highlight,
                branchActive: entry.branchActive && childIsActivePath,
              })),
              {
                hasLine: i < node.children.length - 1,
                highlight: onPath,
                branchActive: childIsActivePath,
              },
            ]
            return (
              <SessionNode
                key={child.session.filePath}
                node={child}
                ancestorLines={newAncestorLines}
                currentSessionPath={currentSessionPath}
                isOnActivePath={childIsActivePath}
                onSwitch={onSwitch}
                onRename={onRename}
                onDelete={onDelete}
                onSetSessionStatus={onSetSessionStatus}
                onForkFromEnd={onForkFromEnd}
                onNewSession={onNewSession}
                onContextMenu={onContextMenu}
                triggerRenamePath={triggerRenamePath}
                onRenameTriggered={onRenameTriggered}
                triggerForkPath={triggerForkPath}
                onForkTriggered={onForkTriggered}
              />
            )
          })}
        </div>
      )}
    </div>
  )
}

function SessionSidebar({
  sessions,
  currentSession,
  onSwitchSession,
  onNewSession,
  onRenameSession,
  onDeleteSession,
  onSetSessionStatus,
  onForkFromEnd,
  isCollapsed,
  onToggleCollapse,
  width,
  onResizeStart,
}: SessionSidebarProps): React.ReactElement {
  const [contextMenu, setContextMenu] = useState<{
    x: number
    y: number
    session: SessionInfo
  } | null>(null)
  const [contextMenuPos, setContextMenuPos] = useState<{ x: number; y: number } | null>(null)
  const [triggerRenamePath, setTriggerRenamePath] = useState<string | null>(null)
  const [triggerForkPath, setTriggerForkPath] = useState<string | null>(null)

  const projects = sessions?.projects ?? []
  const root = projects[0]?.root ?? null

  const handleContextMenu = useCallback((e: React.MouseEvent, session: SessionInfo) => {
    e.preventDefault()
    e.stopPropagation()
    setContextMenu({ x: e.clientX, y: e.clientY, session })
    setContextMenuPos(null) // will be adjusted in useEffect
  }, [])

  const handleRenameTriggered = useCallback(() => {
    setTriggerRenamePath(null)
  }, [])

  const handleForkTriggered = useCallback(() => {
    setTriggerForkPath(null)
  }, [])

  useEffect(() => {
    if (!contextMenu) return

    const handleClick = () => setContextMenu(null)
    const handleKeyDown = (e: KeyboardEvent) => {
      if (e.key === 'Escape') setContextMenu(null)
    }

    document.addEventListener('click', handleClick)
    document.addEventListener('keydown', handleKeyDown)

    return () => {
      document.removeEventListener('click', handleClick)
      document.removeEventListener('keydown', handleKeyDown)
    }
  }, [contextMenu])

  // Adjust context menu position to keep it within viewport
  useEffect(() => {
    if (!contextMenu) return
    const el = document.querySelector('[data-context-menu]') as HTMLDivElement | null
    if (!el) return
    const rect = el.getBoundingClientRect()
    const vw = window.innerWidth
    const vh = window.innerHeight
    let x = contextMenu.x
    let y = contextMenu.y
    if (x + rect.width > vw) x = vw - rect.width - 4
    if (y + rect.height > vh) y = vh - rect.height - 4
    if (x < 0) x = 4
    if (y < 0) y = 4
    setContextMenuPos({ x, y })
  }, [contextMenu])

  if (isCollapsed) {
    return (
      <div className="flex flex-col items-center w-12 bg-gray-50 border-r border-gray-200 pb-3" />
    )
  }

  return (
    <div
      className="relative flex flex-col bg-gray-50 overflow-hidden"
      style={{ width: `${width}px` }}
    >
      <div className="flex-1 overflow-y-auto py-2">
        {projects.length === 0 || !root ? (
          <div className="px-3 py-6 text-center text-xs text-gray-600">
            No sessions found
          </div>
        ) : (
          <SessionNode
            node={root}
            ancestorLines={[]}
            currentSessionPath={currentSession?.filePath ?? null}
            isOnActivePath={true}
            onSwitch={onSwitchSession}
            onRename={onRenameSession}
            onDelete={onDeleteSession}
            onSetSessionStatus={onSetSessionStatus}
            onForkFromEnd={onForkFromEnd}
            onNewSession={onNewSession}
            onContextMenu={handleContextMenu}
            triggerRenamePath={triggerRenamePath}
            onRenameTriggered={handleRenameTriggered}
            triggerForkPath={triggerForkPath}
            onForkTriggered={handleForkTriggered}
          />
        )}
      </div>

      <div
        className="absolute top-0 right-0 w-1 h-full cursor-col-resize hover:w-1.5 hover:bg-blue-500/30 transition-all z-10"
        onMouseDown={onResizeStart}
      />

      {contextMenu && (
        <div
          data-context-menu
          className="fixed z-50 bg-white border border-gray-200 rounded-lg shadow-lg py-1 text-xs min-w-[140px]"
          style={{ left: contextMenuPos?.x ?? contextMenu.x, top: contextMenuPos?.y ?? contextMenu.y }}
          onClick={(e) => e.stopPropagation()}
        >
          <div
            className="px-3 py-1.5 hover:bg-gray-100 cursor-pointer"
            onClick={() => {
              setTriggerRenamePath(contextMenu.session.filePath)
              setContextMenu(null)
            }}
          >
            Rename
          </div>
          <div
            className="px-3 py-1.5 hover:bg-gray-100 cursor-pointer"
            onClick={() => {
              const newStatus = contextMenu.session.status === 'completed' ? 'active' : 'completed'
              onSetSessionStatus(contextMenu.session.filePath, newStatus)
              setContextMenu(null)
            }}
          >
            {contextMenu.session.status === 'completed' ? 'Mark as active' : 'Mark as completed'}
          </div>
          {contextMenu.session.parentSessionPath && (
            <div
              className="px-3 py-1.5 hover:bg-gray-100 cursor-pointer"
              onClick={() => {
                onSwitchSession(contextMenu.session.parentSessionPath!)
                setContextMenu(null)
              }}
            >
              Go to parent
            </div>
          )}
          {contextMenu.session.filePath === currentSession?.filePath && (
            <div
              className="px-3 py-1.5 hover:bg-purple-50 cursor-pointer text-purple-600"
              onClick={() => {
                setTriggerForkPath(contextMenu.session.filePath)
                setContextMenu(null)
              }}
            >
              Fork
            </div>
          )}
          {!contextMenu.session.isMain && (
            <div
              className="px-3 py-1.5 hover:bg-red-50 cursor-pointer text-red-600"
              onClick={() => {
                onDeleteSession(contextMenu.session.filePath)
                setContextMenu(null)
              }}
            >
              Delete
            </div>
          )}
        </div>
      )}
    </div>
  )
}

export default SessionSidebar

import { useState, useEffect, useCallback } from 'react'
import GitLogList from './GitLogList'

interface GitFile {
  path: string
  status: string
  staged: boolean
}

interface GitStatusData {
  branch: string
  ahead: number
  behind: number
  files: GitFile[]
}

function statusLabel(status: string): string {
  switch (status) {
    case 'M': return 'M'
    case 'A': return 'A'
    case 'D': return 'D'
    case '?': return 'U'
    case 'R': return 'R'
    default: return status
  }
}

function statusColor(status: string): string {
  switch (status) {
    case 'M': return 'text-amber-600'
    case 'A': return 'text-green-600'
    case 'D': return 'text-red-500'
    case '?': return 'text-gray-400'
    default: return 'text-gray-500'
  }
}

type SubTab = 'changes' | 'log'

export default function GitPanel({
  onFileSelect,
  onCommitFileSelect,
}: {
  onFileSelect?: (filePath: string) => void
  onCommitFileSelect?: (hash: string, filePath: string) => void
}) {
  const [status, setStatus] = useState<GitStatusData | null>(null)
  const [error, setError] = useState<string | null>(null)
  const [loading, setLoading] = useState(true)
  const [commitMsg, setCommitMsg] = useState('')
  const [committing, setCommitting] = useState(false)
  const [staging, setStaging] = useState<string | null>(null)
  const [subTab, setSubTab] = useState<SubTab>('changes')

  const refresh = useCallback(async () => {
    setLoading(true)
    setError(null)
    try {
      const result = await window.api.gitStatus()
      if (result.ok && result.data) {
        setStatus(result.data)
      } else {
        setError(result.error ?? 'Failed to get git status')
        setStatus(null)
      }
    } catch (err) {
      setError(err instanceof Error ? err.message : String(err))
      setStatus(null)
    } finally {
      setLoading(false)
    }
  }, [])

  useEffect(() => {
    refresh()
  }, [refresh])

  useEffect(() => {
    const api = window.api as typeof window.api & { onFsChanged?: (cb: () => void) => () => void }
    if (!api.onFsChanged) return
    let timer: ReturnType<typeof setTimeout> | null = null
    const unsub = api.onFsChanged(() => {
      if (timer) clearTimeout(timer)
      timer = setTimeout(refresh, 500)
    })
    return () => {
      unsub()
      if (timer) clearTimeout(timer)
    }
  }, [refresh])

  const handleStage = useCallback(async (filePath: string) => {
    setStaging(filePath)
    try {
      const result = await window.api.gitStage([filePath])
      if (result.ok) await refresh()
    } finally {
      setStaging(null)
    }
  }, [refresh])

  const handleUnstage = useCallback(async (filePath: string) => {
    setStaging(filePath)
    try {
      const result = await window.api.gitUnstage([filePath])
      if (result.ok) await refresh()
    } finally {
      setStaging(null)
    }
  }, [refresh])

  const handleStageAll = useCallback(async () => {
    if (!status) return
    const paths = status.files.filter(f => !f.staged).map(f => f.path)
    if (paths.length === 0) return
    setStaging('__all__')
    try {
      await window.api.gitStage(paths)
      await refresh()
    } finally {
      setStaging(null)
    }
  }, [status, refresh])

  const handleDiscardAll = useCallback(async () => {
    if (!status) return
    const paths = status.files.filter(f => !f.staged && f.status !== '?').map(f => f.path)
    if (paths.length === 0) return
    setStaging('__discard__')
    try {
      await window.api.gitDiscard(paths)
      await refresh()
    } finally {
      setStaging(null)
    }
  }, [status, refresh])

  const handleCommit = useCallback(async () => {
    if (!commitMsg.trim()) return
    setCommitting(true)
    try {
      const result = await window.api.gitCommit(commitMsg.trim())
      if (result.ok) {
        setCommitMsg('')
        await refresh()
      }
    } finally {
      setCommitting(false)
    }
  }, [commitMsg, refresh])

  if (loading) {
    return (
      <div className="flex items-center justify-center h-full text-gray-400 text-xs">
        Loading...
      </div>
    )
  }

  if (error) {
    return (
      <div className="p-3 text-xs text-gray-400">
        {error}
      </div>
    )
  }

  if (!status) return null

  const staged = status.files.filter(f => f.staged)
  const unstaged = status.files.filter(f => !f.staged && f.status !== '?')
  const untracked = status.files.filter(f => f.status === '?')

  const hasUnstagedOrUntracked = unstaged.length > 0 || untracked.length > 0
  const hasUnstagedChanges = unstaged.length > 0

  return (
    <div className="text-xs flex flex-col h-full">
      {/* Branch header */}
      <div className="px-3 py-2 border-b border-gray-200 flex items-center gap-2 flex-shrink-0">
        <span className="font-medium text-gray-700">{status.branch}</span>
        {status.ahead > 0 && <span className="text-green-600">↑{status.ahead}</span>}
        {status.behind > 0 && <span className="text-amber-600">↓{status.behind}</span>}
        {hasUnstagedOrUntracked && (
          <div className="ml-auto flex items-center gap-1">
            <button
              onClick={handleStageAll}
              className="rounded p-1 text-gray-400 hover:text-green-600 hover:bg-gray-100 transition-colors"
              disabled={staging !== null}
              title="Stage All"
            >
              <svg className="w-3.5 h-3.5" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2}>
                <path strokeLinecap="round" strokeLinejoin="round" d="M12 4v16m8-8H4" />
              </svg>
            </button>
            {hasUnstagedChanges && (
              <button
                onClick={handleDiscardAll}
                className="rounded p-1 text-gray-400 hover:text-red-500 hover:bg-gray-100 transition-colors"
                disabled={staging !== null}
                title="Discard All Changes"
              >
                <svg className="w-3.5 h-3.5" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2}>
                  <path strokeLinecap="round" strokeLinejoin="round" d="M20 12H4" />
                </svg>
              </button>
            )}
          </div>
        )}
        {!hasUnstagedOrUntracked && (
          <button
            onClick={refresh}
            className="ml-auto rounded p-1 text-gray-400 hover:text-gray-600 hover:bg-gray-100 transition-colors"
            title="Refresh"
          >
            <svg className="w-3.5 h-3.5" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2}>
              <path strokeLinecap="round" strokeLinejoin="round" d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15" />
            </svg>
          </button>
        )}
      </div>

      {/* Sub-tab: Changes / Log */}
      <div className="flex border-b border-gray-200 flex-shrink-0">
        <button
          onClick={() => setSubTab('changes')}
          className={`flex-1 py-1.5 text-xs font-medium transition-colors ${
            subTab === 'changes'
              ? 'text-blue-600 border-b-2 border-blue-600'
              : 'text-gray-500 hover:text-gray-700'
          }`}
        >
          Changes
          {status.files.length > 0 && (
            <span className="ml-1 text-[10px] text-gray-400">({status.files.length})</span>
          )}
        </button>
        <button
          onClick={() => setSubTab('log')}
          className={`flex-1 py-1.5 text-xs font-medium transition-colors ${
            subTab === 'log'
              ? 'text-blue-600 border-b-2 border-blue-600'
              : 'text-gray-500 hover:text-gray-700'
          }`}
        >
          Log
        </button>
      </div>

      {/* Content area */}
      <div className="flex-1 overflow-y-auto min-h-0">
        {subTab === 'changes' && (
          <>
            {staged.length > 0 && (
              <div className="border-b border-gray-200">
                <div className="px-3 py-1.5 text-gray-500 font-medium">Staged Changes ({staged.length})</div>
                {staged.map(f => (
                  <div key={f.path} className="px-3 py-1 flex items-center gap-1 hover:bg-gray-100 group" title={f.path}>
                    <span className={`w-4 text-center font-mono font-semibold ${statusColor(f.status)}`}>{statusLabel(f.status)}</span>
                    <span className="text-gray-700 truncate flex-1 cursor-pointer" onClick={() => onFileSelect?.(f.path)}>{f.path}</span>
                    <button
                      onClick={() => handleUnstage(f.path)}
                      disabled={staging !== null}
                      className="rounded p-0.5 text-gray-400 hover:text-gray-600 hover:bg-gray-200 opacity-0 group-hover:opacity-100 transition-opacity flex-shrink-0"
                      title="Unstage"
                    >
                      <svg className="w-3 h-3" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2}>
                        <path strokeLinecap="round" strokeLinejoin="round" d="M20 12H4" />
                      </svg>
                    </button>
                  </div>
                ))}
              </div>
            )}

            {unstaged.length > 0 && (
              <div className="border-b border-gray-200">
                <div className="px-3 py-1.5 text-gray-500 font-medium">Changes ({unstaged.length})</div>
                {unstaged.map(f => (
                  <div key={f.path} className="px-3 py-1 flex items-center gap-1 hover:bg-gray-100 group" title={f.path}>
                    <span className={`w-4 text-center font-mono font-semibold ${statusColor(f.status)}`}>{statusLabel(f.status)}</span>
                    <span className="text-gray-700 truncate flex-1 cursor-pointer" onClick={() => onFileSelect?.(f.path)}>{f.path}</span>
                    <button
                      onClick={() => handleStage(f.path)}
                      disabled={staging !== null}
                      className="rounded p-0.5 text-gray-400 hover:text-green-600 hover:bg-gray-200 opacity-0 group-hover:opacity-100 transition-opacity flex-shrink-0"
                      title="Stage"
                    >
                      <svg className="w-3 h-3" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2}>
                        <path strokeLinecap="round" strokeLinejoin="round" d="M12 4v16m8-8H4" />
                      </svg>
                    </button>
                  </div>
                ))}
              </div>
            )}

            {untracked.length > 0 && (
              <div className="border-b border-gray-200">
                <div className="px-3 py-1.5 text-gray-500 font-medium">Untracked ({untracked.length})</div>
                {untracked.map(f => (
                  <div key={f.path} className="px-3 py-1 flex items-center gap-1 hover:bg-gray-100 group" title={f.path}>
                    <span className={`w-4 text-center font-mono font-semibold ${statusColor(f.status)}`}>U</span>
                    <span className="text-gray-700 truncate flex-1 cursor-pointer" onClick={() => onFileSelect?.(f.path)}>{f.path}</span>
                    <button
                      onClick={() => handleStage(f.path)}
                      disabled={staging !== null}
                      className="rounded p-0.5 text-gray-400 hover:text-green-600 hover:bg-gray-200 opacity-0 group-hover:opacity-100 transition-opacity flex-shrink-0"
                      title="Stage"
                    >
                      <svg className="w-3 h-3" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2}>
                        <path strokeLinecap="round" strokeLinejoin="round" d="M12 4v16m8-8H4" />
                      </svg>
                    </button>
                  </div>
                ))}
              </div>
            )}

            {status.files.length === 0 && (
              <div className="px-3 py-4 text-gray-400 text-center">
                No changes
                <div className="mt-1 text-[10px]">
                  Switch to <button onClick={() => setSubTab('log')} className="text-blue-500 hover:underline">Log</button> to see commit history
                </div>
              </div>
            )}
          </>
        )}

        {subTab === 'log' && (
          <GitLogList onCommitFileSelect={onCommitFileSelect} />
        )}
      </div>

      {/* Commit input (only in Changes tab with staged files) */}
      {subTab === 'changes' && staged.length > 0 && (
        <div className="border-t border-gray-200 p-2 flex-shrink-0">
          <textarea
            value={commitMsg}
            onChange={e => setCommitMsg(e.target.value)}
            onKeyDown={e => {
              if (e.key === 'Enter' && (e.metaKey || e.ctrlKey) && commitMsg.trim()) {
                e.preventDefault()
                handleCommit()
              }
            }}
            placeholder="Commit message (⌘+Enter)"
            className="w-full resize-none border border-gray-200 rounded px-2 py-1.5 text-xs focus:outline-none focus:border-blue-400"
            rows={2}
            disabled={committing}
          />
          <button
            onClick={handleCommit}
            disabled={!commitMsg.trim() || committing}
            className="w-full mt-1 rounded bg-blue-600 px-3 py-1.5 text-xs font-medium text-white hover:bg-blue-500 disabled:bg-gray-300 disabled:cursor-not-allowed transition-colors"
          >
            {committing ? 'Committing...' : 'Commit'}
          </button>
        </div>
      )}
    </div>
  )
}

